const items = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);
const OWNER_ID = process.env.OWNER_TELEGRAM_ID || '7970044894';

const toSend = [];
const expiredList = [];
const warnList = [];

for (const item of items) {
  const r = item.json;
  if (!r.client_id || !r.end_date) continue;
  if (r.status === 'expired' || r.status === 'suspended') continue;

  const parts = r.end_date.toString().split('/');
  if (parts.length !== 3) continue;
  const endDate = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
  if (isNaN(endDate.getTime())) continue;

  const daysLeft = Math.ceil((endDate - today) / 86400000);
  const pkg = (r.package || '').charAt(0).toUpperCase() + (r.package || '').slice(1);
  const price = parseInt(r.monthly_price || 0).toLocaleString('vi-VN');
  const ownerName = r.owner_name || r.name || 'ban';

  if (daysLeft <= 0) {
    expiredList.push(r.name + ' (het han ' + r.end_date + ')');
    if (r.telegram_chat_id) {
      toSend.push({
        telegram_id: r.telegram_chat_id,
        message: '🔴 HET HAN DICH VU — AgentWell\n\nChao ' + ownerName + '!\n\nGoi ' + pkg + ' cua ban da het han ngay ' + r.end_date + '.\n\nBot se DUNG hoat dong trong 24h.\n\nDe gia han dich vu:\nZalo: 0905 544 556\nWeb: agentwell.vercel.app\n\nCam on ban da tin tuong AgentWell!'
      });
    }
  } else if (daysLeft <= 7) {
    warnList.push(r.name + ' (con ' + daysLeft + ' ngay)');
    if (r.telegram_chat_id && [1, 3, 7].includes(daysLeft)) {
      const emoji = daysLeft === 1 ? '🚨' : daysLeft === 3 ? '⚠️' : '📢';
      toSend.push({
        telegram_id: r.telegram_chat_id,
        message: emoji + ' NHAC GIA HAN — Con ' + daysLeft + ' ngay\n\nChao ' + ownerName + '!\n\nGoi ' + pkg + ' cua ban het han ngay ' + r.end_date + '.\nPhi gia han: ' + price + ' VND/thang\n\nGia han de bot tiep tuc hoat dong 24/7:\nZalo: 0905 544 556\nWeb: agentwell.vercel.app'
      });
    }
  }
}

if (expiredList.length > 0 || warnList.length > 0) {
  let ownerMsg = '📊 SUBSCRIPTION REPORT — AgentWell\n====================';
  if (expiredList.length > 0) {
    ownerMsg += '\n\n🔴 DA HET HAN (' + expiredList.length + ' khach):';
    expiredList.forEach(x => { ownerMsg += '\n  - ' + x; });
    ownerMsg += '\n  → Vao n8n tat workflow cua khach nay';
  }
  if (warnList.length > 0) {
    ownerMsg += '\n\n⚠️ SAP HET HAN:';
    warnList.forEach(x => { ownerMsg += '\n  - ' + x; });
  }
  ownerMsg += '\n\n📱 Da gui nhac toi khach hang.';
  toSend.push({ telegram_id: OWNER_ID, message: ownerMsg });
}

if (toSend.length === 0) {
  return [{ json: { skip: true, message: 'Khong co khach sap het han hom nay' } }];
}
return toSend.map(t => ({ json: t }));
